// FAST CRUISE DATA EXTRACTOR FOR N8N
// Execute time: < 1 second

const body = items[0]?.json?.Body || '';

// Extract cruise entries using regex - Very Fast!
const cruisePattern = /([A-Za-z\s]+?)(\d{2}\/\d{2}\/\d{4})(\d{2}\/\d{2}\/\d{4})Book Parking/g;
const matches = [...body.matchAll(cruisePattern)];

const cruises = matches.map(match => {
  const shipName = match[1].trim().replace(/\s+/g, ' ');
  const departure = match[2];
  const arrival = match[3];

  // Parse dates for filtering
  const [d, m, y] = departure.split('/');
  const dateObj = new Date(`${y}-${m}-${d}`);

  return {
    ship_name: shipName,
    departure_date: departure,
    arrival_date: arrival,
    duration_days: Math.ceil((new Date(arrival.split('/')[2], arrival.split('/')[1]-1, arrival.split('/')[0]) - dateObj) / (1000 * 60 * 60 * 24)),
    month: dateObj.toLocaleString('en-US', { month: 'long' }),
    year: y,
    booking_available: true
  };
});

// Optional: Filter by month if userQuery provided
const userQuery = items[0]?.json?.userQuery || '';
let filteredCruises = cruises;

if (userQuery) {
  const query = userQuery.toLowerCase();
  filteredCruises = cruises.filter(c => 
    c.month.toLowerCase().includes(query) ||
    c.ship_name.toLowerCase().includes(query) ||
    c.year.includes(query)
  );
}

// Return formatted data
return [{
  json: {
    total_found: filteredCruises.length,
    filter_applied: userQuery || 'none',
    cruises: filteredCruises
  }
}];
